import numpy as np
from sentence_transformers import SentenceTransformer, InputExample
from transformers import pipeline
from annoy import AnnoyIndex
import pickle

# Load company documents into vector database
def load_documents(vector_db_path):
    with open(vector_db_path, 'rb') as f:
        doc_vectors = pickle.load(f)
    return doc_vectors

# Create a SentenceTransformer model for document embeddings
model = SentenceTransformer('paraphrase-multilingual-mpnet-base-v2')

# Load company documents into vector database
vector_db_path = 'company_documents.pkl'
doc_vectors = load_documents(vector_db_path)

# Create an Annoy index for efficient nearest neighbor search
dim = doc_vectors.shape[1]
annoy_index = AnnoyIndex(dim, 'angular')
for i, vec in enumerate(doc_vectors):
    annoy_index.add_item(i, vec)
annoy_index.build(10)  # build the tree with 10 threads

# Define a function to retrieve relevant documents for a given query
def retrieve_documents(query):
    query_vector = model.encode(query)
    nearest_neighbors = annoy_index.get_nns_by_vector(query_vector, 10, search_k=-1, include_distances=True)
    return nearest_neighbors[0]

# Define a function to generate an LLM prompt with retrieved documents
def generate_llm_prompt(doc_ids):
    retrieved_docs = [doc_vectors[i] for i in doc_ids]
    llm_prompt = ' '.join([f'Document {i}: {doc}' for i, doc in enumerate(retrieved_docs)])
    return llm_prompt

# Define a function to interact with the LLM model
def interact_with_llm(query):
    retrieved_doc_ids = retrieve_documents(query)
    llm_prompt = generate_llm_prompt(retrieved_doc_ids)
    llm_model = pipeline('text-generation')
    response = llm_model(llm_prompt, max_length=1024, num_return_sequences=1)[0]['generated_text']
    return response

# Main loop to interact with the user
while True:
    query = input("Enter your question: ")
    response = interact_with_llm(query)
    print(response)